mapper.select:
select tenant_id, metadata_json ->> 'fileGroupCode' as file_group_code, coalesce(metadata_json ->> 'waitFileGroupMode', 'ALL_OF') as wait_file_group_mode, coalesce(metadata_json ->> 'requiredFileSet', '') as required_file_set, coalesce(metadata_json ->> 'arrivalTimeoutAction', 'MANUAL_CONFIRM') as arrival_timeout_action, coalesce(metadata_json ->> 'arrivalState', 'WAITING_ARRIVAL') as arrival_state, nullif(metadata_json ->> 'expectedArrivalTime', '')::timestamptz as expected_arrival_time, nullif(metadata_json ->> 'latestTolerableTime', '')::timestamptz as latest_tolerable_time, count(1) as arrived_count, count(1) filter (where coalesce(metadata_json ->> 'arrivalState', 'WAITING_ARRIVAL') = 'TRIGGERED') as triggered_count, count(1) filter (where coalesce(metadata_json ->> 'arrivalState', 'WAITING_ARRIVAL') = 'TIMEOUT') as timeout_count, count(1) filter (where coalesce(metadata_json ->> 'arrivalState', 'WAITING_ARRIVAL') like 'WAITING%') as waiting_count, max(updated_at) as last_updated_at from batch.file_record where jsonb_exists(metadata_json, 'fileGroupCode')
and tenant_id = #{tenantId}
and metadata_json ->> 'fileGroupCode' = #{fileGroupCode}
and coalesce(metadata_json ->> 'arrivalState', 'WAITING_ARRIVAL') = #{arrivalState}
and created_at >= #{fromTime}
and created_at <= #{toTime}
group by tenant_id, metadata_json ->> 'fileGroupCode', coalesce(metadata_json ->> 'waitFileGroupMode', 'ALL_OF'), coalesce(metadata_json ->> 'requiredFileSet', ''), coalesce(metadata_json ->> 'arrivalTimeoutAction', 'MANUAL_CONFIRM'), coalesce(metadata_json ->> 'arrivalState', 'WAITING_ARRIVAL'), nullif(metadata_json ->> 'expectedArrivalTime', '')::timestamptz, nullif(metadata_json ->> 'latestTolerableTime', '')::timestamptz order by last_updated_at desc, file_group_code asc
limit #{pageRequest.pageSize} offset (#{pageRequest.pageNo} - 1) * #{pageRequest.pageSize}

select count(1)
from (
    select 1
    from batch.file_record
    where jsonb_exists(metadata_json, 'fileGroupCode')

          and tenant_id = #{tenantId}


          and metadata_json ->> 'fileGroupCode' = #{fileGroupCode}


          and coalesce(metadata_json ->> 'arrivalState', 'WAITING_ARRIVAL') = #{arrivalState}


          and created_at >= #{fromTime}


          and created_at <= #{toTime}

    group by tenant_id,
             metadata_json ->> 'fileGroupCode',
             coalesce(metadata_json ->> 'waitFileGroupMode', 'ALL_OF'),
             coalesce(metadata_json ->> 'requiredFileSet', ''),
             coalesce(metadata_json ->> 'arrivalTimeoutAction', 'MANUAL_CONFIRM'),
             coalesce(metadata_json ->> 'arrivalState', 'WAITING_ARRIVAL'),
             nullif(metadata_json ->> 'expectedArrivalTime', '')::timestamptz,
             nullif(metadata_json ->> 'latestTolerableTime', '')::timestamptz
) t
